const inputData = $input.all();

const attendanceRecords = Array.isArray(inputData[0].json) ? inputData[0].json : (inputData[0].json.records || inputData[0].json.data || []);
const workers = Array.isArray(inputData[1].json) ? inputData[1].json : (inputData[1].json.workers || inputData[1].json.data || []);

// Build worker lookup
const workerMap = {};
workers.forEach(w => { workerMap[w.id] = w; });

// Aggregate attendance per worker
const workerStats = {};
attendanceRecords.forEach(record => {
  const wid = record.worker_id || record.workerId;
  if (!workerStats[wid]) {
    workerStats[wid] = {
      workerId: wid,
      workerName: workerMap[wid]?.name || `Worker #${wid}`,
      totalDays: 0,
      onTime: 0,
      late: 0,
      absent: 0,
      totalHours: 0,
      days: []
    };
  }

  const status = (record.status || 'present').toLowerCase();
  workerStats[wid].totalDays++;

  if (status === 'present' || status === 'on_time') {
    workerStats[wid].onTime++;
  } else if (status === 'late') {
    workerStats[wid].late++;
  } else if (status === 'absent') {
    workerStats[wid].absent++;
  }

  workerStats[wid].totalHours += record.hours_worked || record.hours || 0;
  workerStats[wid].days.push({
    date: record.date,
    status: status,
    hours: record.hours_worked || record.hours || 0
  });
});

const reportRows = Object.values(workerStats).map(ws => ({
  ...ws,
  attendanceRate: ws.totalDays > 0 ? Math.round((ws.onTime / ws.totalDays) * 100) : 0,
  avgHours: ws.totalDays > 0 ? (ws.totalHours / ws.totalDays).toFixed(1) : 0
}));

reportRows.sort((a, b) => a.attendanceRate - b.attendanceRate);

// Generate CSV
const csvHeader = 'Worker ID,Worker Name,Total Days,On Time,Late,Absent,Attendance %,Total Hours,Avg Hours/Day\n';
const csvRows = reportRows.map(r => 
  `${r.workerId},${r.workerName},${r.totalDays},${r.onTime},${r.late},${r.absent},${r.attendanceRate}%,${r.totalHours.toFixed(1)},${r.avgHours}`
).join('\n');

const csvContent = csvHeader + csvRows;

// Generate summary message
const totalWorkers = reportRows.length;
const avgAttendance = totalWorkers > 0 ? Math.round(reportRows.reduce((s, r) => s + r.attendanceRate, 0) / totalWorkers) : 0;
const totalLate = reportRows.reduce((s, r) => s + r.late, 0);
const totalAbsent = reportRows.reduce((s, r) => s + r.absent, 0);

const problemWorkers = reportRows.filter(r => r.attendanceRate < 80);

let message = `📊 *Weekly Attendance Report*\n\n`;
message += `📅 Week: Last Week\n`;
message += `👥 Workers tracked: ${totalWorkers}\n`;
message += `📈 Avg attendance rate: ${avgAttendance}%\n`;
message += `⏰ Total late arrivals: ${totalLate}\n`;
message += `❌ Total absences: ${totalAbsent}\n\n`;

if (problemWorkers.length > 0) {
  message += `⚠️ *Workers needing attention (<80% attendance):*\n`;
  problemWorkers.forEach(w => {
    message += `• ${w.workerName}: ${w.attendanceRate}% (${w.late} late, ${w.absent} absent)\n`;
  });
}

return {
  summary: message,
  report: reportRows,
  csvContent: csvContent,
  totalWorkers: totalWorkers,
  avgAttendance: avgAttendance,
  problemWorkers: problemWorkers.length
};
